# [doc = " `spore publish --registry <dir>` — the M-732 local, file-based store."] fn run_publish_local (spore : & Spore , registry_dir : & Path , opts : & Opts) -> ExitCode { let (name , version) = match publish_name_version (spore , opts) { Ok (nv) => nv , Err (code) => return code , } ; let descriptor = explain (spore) . into_bytes () ; match registry :: publish (registry_dir , spore , & descriptor , & name , & version) { Ok (r) => { let state = if r . already_present { "already present" } else { "published" } ; eprintln ! ("spore: {state} {name}@{version}
  spore_id: {}
  artifact: {}
  object:   {}" , r . spore_id . as_str () , r . artifact . as_str () , r . object_path . display ()) ; ExitCode :: SUCCESS } Err (e) => { eprintln ! ("spore: {e}") ; ExitCode :: from (e . exit_code ()) } } }

# [doc = " `spore publish --registry oci://…|ghcr://…` — the ADR-037 remote OCI/GHCR backend, driven by"] # [doc = " `oras` ([`remote::OrasTransport`]). `oras` absent or failing is an explicit, actionable error"] # [doc = " (never a silent skip — ADR-037 §5)."] fn run_publish_remote (spore : & Spore , project_dir : & Path , target : & RegistryTarget , opts : & Opts ,) -> ExitCode { let (name , version) = match publish_name_version (spore , opts) { Ok (nv) => nv , Err (code) => return code , } ; let plain_http = matches ! (target , RegistryTarget :: Oci { plain_http : true , .. }) ; let transport = remote :: OrasTransport { plain_http } ; match remote :: publish_remote (target , spore , project_dir , & name , & version , & transport) { Ok (r) => { eprintln ! ("spore: published {name}@{version}
  reference:        {}
  manifest digest:  {}
  spore_id:         {}" , r . reference , r . manifest_digest , r . spore_id . as_str ()) ; ExitCode :: SUCCESS } Err (e) => { eprintln ! ("spore: {e}") ; ExitCode :: from (e . exit_code ()) } } }

# [doc = " The canonical, deterministic identity encoding (ADR-003) — **the single source of truth for spore"] # [doc = " identity**. Metadata (`name`/`version`/`authors`/…) is **excluded** — only the code-by-hash DAG, the"] # [doc = " dependency hash edges, the germination surface, and the project kind bear identity. Two builds of the"] # [doc = " same code+deps yield the same spore hash. **Downstream verifiers (e.g. `mycelium-std-spore::verify`)"] # [doc = " MUST call this function — never re-implement the encoding:** a parallel copy is exactly how the"] # [doc = " `v0`/`v1` split arose (DRY; the verify path stamped a stale `v0` while `build_spore` stamped `v1`)."] pub fn content_address (kind : ProjectKind , surface : & [String] , sources : & [SourceFile] , deps : & [ResolvedDep] ,) -> ContentHash { let mut s = String :: from ("mycelium-spore-v1
") ; s . push_str (& format ! ("kind:{}
" , kind_str (kind))) ; s . push_str (& format ! ("surface:{}
" , surface . len ())) ; for name in surface { push_field (& mut s , name) ; } s . push_str (& format ! ("code:{}
" , sources . len ())) ; for f in sources { push_field (& mut s , & f . path) ; push_field (& mut s , f . hash . as_str ()) ; } s . push_str (& format ! ("deps:{}
" , deps . len ())) ; for d in deps { push_field (& mut s , & d . name) ; push_field (& mut s , & d . phylum) ; push_field (& mut s , & d . hash) ; } let hex = blake3 :: hash (s . as_bytes ()) . to_hex () ; ContentHash :: from_parts ("blake3" , hex . as_str ()) . expect ("blake3 hex is a valid digest") }

fn walk (root : & Path , dir : & Path , depth : usize , out : & mut Vec < SourceFile > ,) -> Result < () , SporeError > { if depth > MAX_WALK_DEPTH { return Err (SporeError :: Publish (format ! ("source tree under {} nests deeper than {MAX_WALK_DEPTH} directories at {} — refusing \
             to recurse further (a tree this deep is not a valid layout; likely a symlink cycle or \
             an adversarial input). Flatten the tree or remove the offending link (DN-40/G2)" , root . display () , dir . display () ,))) ; } let entries = std :: fs :: read_dir (dir) . map_err (| e | SporeError :: Io (format ! ("{}: {e}" , dir . display ()))) ? ; let mut paths : Vec < PathBuf > = entries . filter_map (| e | e . ok () . map (| e | e . path ())) . collect () ; paths . sort () ; for path in paths { let name = path . file_name () . and_then (| s | s . to_str ()) . unwrap_or_default () ; if name . starts_with ('.') || name == "target" { continue ; } let meta = std :: fs :: symlink_metadata (& path) . map_err (| e | SporeError :: Io (format ! ("{}: {e}" , path . display ()))) ? ; if meta . file_type () . is_symlink () { continue ; } if meta . is_dir () { walk (root , & path , depth + 1 , out) ? ; } else if meta . is_file () && path . extension () . is_some_and (| x | x == "myc") { let bytes = std :: fs :: read (& path) . map_err (| e | SporeError :: Io (format ! ("{}: {e}" , path . display ()))) ? ; let hex = blake3 :: hash (& bytes) . to_hex () ; let hash = ContentHash :: from_parts ("blake3" , hex . as_str ()) . expect ("blake3 hex is a valid digest") ; let rel = path . strip_prefix (root) . unwrap_or (& path) . to_string_lossy () . replace ('\\' , "/") ; out . push (SourceFile { path : rel , hash }) ; } } Ok (()) }

# [doc = " The `EXPLAIN` of a built spore (no black box): the identity receipt, the surface, the code by hash, the"] # [doc = " dependency edges, and the metadata — the metadata explicitly marked *not* identity (ADR-003)."] # [must_use] pub fn explain (spore : & Spore) -> String { let mut out = format ! ("spore: {}  →  {}
" , spore . name , spore . id . as_str ()) ; out . push_str (& format ! ("  kind:    {}
" , kind_str (spore . kind))) ; out . push_str (& format ! ("  surface: {}
" , spore . surface . join (", "))) ; out . push_str (& format ! ("  code:    {} source file(s)
" , spore . sources . len ())) ; for f in & spore . sources { out . push_str (& format ! ("    {} {}
" , f . path , f . hash . as_str ())) ; } out . push_str (& format ! ("  deps:    {}
" , spore . deps . len ())) ; for d in & spore . deps { let v = d . version . as_deref () . unwrap_or ("*") ; out . push_str (& format ! ("    {} → {} {} (version {v})
" , d . name , d . phylum , d . hash)) ; } let ver = spore . version . as_deref () . unwrap_or ("—") ; out . push_str (& format ! ("  metadata: name={}, version={ver}  [not identity — ADR-003]
" , spore . name)) ; out }

# [doc = " **Publish** `spore`'s `descriptor` bytes under `name@version` into the registry at `root`."] # [doc = ""] # [doc = " The descriptor bytes are content-addressed (BLAKE3 → `artifact`), stored once under"] # [doc = " `objects/`, and pointed at by an `index/<name>/<version>` entry recording both the `artifact`"] # [doc = " integrity hash and the `spore_id` DAG identity (ADR-003). Idempotent for an identical"] # [doc = " re-publish; a *different* artifact under an existing `name@version` is a refused"] # [doc = " [`RegistryError::Conflict`] (immutability, G2). The integrity hash is verified by reading the"] # [doc = " object back after write."] # [doc = ""] # [doc = " # Errors"] # [doc = " [`RegistryError::InvalidInput`] for an empty `version`; [`RegistryError::Conflict`] on an"] # [doc = " immutability violation; [`RegistryError::Integrity`] if the written object fails read-back"] # [doc = " verification; [`RegistryError::Io`] on a filesystem failure."] pub fn publish (root : & Path , spore : & Spore , descriptor : & [u8] , name : & str , version : & str ,) -> Result < PublishReceipt , RegistryError > { if version . trim () . is_empty () { return Err (RegistryError :: InvalidInput ("a publish needs a non-empty version label (it is never guessed; ADR-003 metadata)" . to_owned () ,)) ; } safe_component ("name" , name) ? ; safe_component ("version" , version) ? ; let artifact = artifact_hash (descriptor) ; let obj = object_path (root , & artifact) ; let mut already_present = false ; if obj . exists () { let existing = std :: fs :: read (& obj) . map_err (| e | io (& obj . display () . to_string () , e)) ? ; if existing != descriptor { return Err (RegistryError :: Integrity (format ! ("object {} exists but its bytes do not match the artifact hash — store corruption" , obj . display ()))) ; } already_present = true ; } else { if let Some (parent) = obj . parent () { std :: fs :: create_dir_all (parent) . map_err (| e | io (& parent . display () . to_string () , e)) ? ; } std :: fs :: write (& obj , descriptor) . map_err (| e | io (& obj . display () . to_string () , e)) ? ; let back = std :: fs :: read (& obj) . map_err (| e | io (& obj . display () . to_string () , e)) ? ; if artifact_hash (& back) != artifact { return Err (RegistryError :: Integrity (format ! ("post-write verification of {} failed — artifact hash mismatch" , obj . display ()))) ; } } let idx = index_path (root , name , version) ; let entry = format_entry (& spore . id , & artifact) ; if idx . exists () { let existing = std :: fs :: read_to_string (& idx) . map_err (| e | io (& idx . display () . to_string () , e)) ? ; let (prev_id , prev_art) = parse_entry (& existing) . map_err (| e | RegistryError :: Integrity (format ! ("{} — {e}" , idx . display ()))) ? ; if prev_id != spore . id || prev_art != artifact { return Err (RegistryError :: Conflict (format ! ("{name}@{version} is already published with a different artifact \
                 (have spore_id={}, artifact={}); publishing a new artifact requires a new version \
                 — a registry is immutable (G2)" , prev_id . as_str () , prev_art . as_str ()))) ; } } else { if let Some (parent) = idx . parent () { std :: fs :: create_dir_all (parent) . map_err (| e | io (& parent . display () . to_string () , e)) ? ; } std :: fs :: write (& idx , entry) . map_err (| e | io (& idx . display () . to_string () , e)) ? ; } Ok (PublishReceipt { name : name . to_owned () , version : version . to_owned () , spore_id : spore . id . clone () , artifact , object_path : obj , already_present , }) }

# [doc = " Encode a [`DenseMap`] into its canonical, deterministic, injective, length-prefixed bytes"] # [doc = " (ADR-037 §2) — the OCI config blob payload. **Injectivity is the whole contract**, same as"] # [doc = " [`crate::content_address`]: every free-text field (`name`, `version`, `rel_path`, dependency"] # [doc = " `name`/`phylum`/`hash`/`version`) is length-prefixed so an embedded space/newline/colon cannot"] # [doc = " alias two distinct dense-maps onto one encoding. Fixed-vocabulary fields (`kind`) and"] # [doc = " already-charset-restricted fields (`ContentHash`, which cannot contain a newline by construction"] # [doc = " — [`ContentHash::parse`]) are written as plain lines. Sections are sorted here (`surface`,"] # [doc = " `objects` by `rel_path`, `deps` by name) regardless of input order, so two [`DenseMap`]s with the"] # [doc = " same logical content always encode identically."] # [must_use] pub fn encode_dense_map (dm : & DenseMap) -> Vec < u8 > { let mut surface = dm . surface . clone () ; surface . sort () ; let mut objects = dm . objects . clone () ; objects . sort_by (| a , b | a . rel_path . cmp (& b . rel_path)) ; let mut deps = dm . deps . clone () ; deps . sort_by (| a , b | a . name . cmp (& b . name)) ; let mut out = String :: from (DENSE_MAP_HEADER) ; out . push_str (& format ! ("spore_id:{}
" , dm . spore_id . as_str ())) ; out . push_str (& format ! ("kind:{}
" , kind_str (dm . kind))) ; out . push_str ("name:") ; push_len_field (& mut out , & dm . name) ; push_opt_field (& mut out , "version:" , dm . version . as_deref ()) ; out . push_str (& format ! ("surface {}
" , surface . len ())) ; for s in & surface { push_len_field (& mut out , s) ; } out . push_str (& format ! ("objects {}
" , objects . len ())) ; for o in & objects { out . push_str ("objpath:") ; push_len_field (& mut out , & o . rel_path) ; out . push_str (& format ! ("objhash:{}
" , o . content_hash . as_str ())) ; } out . push_str (& format ! ("deps {}
" , deps . len ())) ; for d in & deps { out . push_str ("depname:") ; push_len_field (& mut out , & d . name) ; out . push_str ("depphylum:") ; push_len_field (& mut out , & d . phylum) ; out . push_str ("dephash:") ; push_len_field (& mut out , & d . hash) ; push_opt_field (& mut out , "depversion:" , d . version . as_deref ()) ; } out . into_bytes () }

# [doc = " Spawn `oras`, mapping a missing binary to [`RemoteError::ToolMissing`] (never a silent skip) and"] # [doc = " any other spawn failure to [`RemoteError::Transport`]."] fn spawn_oras (mut cmd : Command) -> Result < std :: process :: Output , RemoteError > { cmd . output () . map_err (| e | { if e . kind () == std :: io :: ErrorKind :: NotFound { RemoteError :: ToolMissing ("the `oras` CLI is not on PATH — it is the v0 OCI wire-transport driver (ADR-037 §1); \
                 install it (https://oras.land) or publish/resolve against a local (non-`oci://`/`ghcr://`) \
                 registry path instead" . to_owned () ,) } else { RemoteError :: Transport (format ! ("failed to spawn `oras`: {e}")) } }) }
